@echo off
chcp 65001 >nul
echo ========================================
echo    OpenClaw 自动同步备份脚本
echo ========================================
echo.

echo [1/4] 同步主配置仓库 (.openclaw)
cd /d %USERPROFILE%\.openclaw
git add .
if %errorlevel% neq 0 (
    echo 错误：git add 失败
    pause
    exit /b 1
)

for /f "delims=" %%i in ('git diff --cached --name-only') do set HAS_CHANGES=%%i
if defined HAS_CHANGES (
    git commit -m "自动备份 %date:~0,4%-%date:~5,2%-%date:~8,2% %time:~0,2%:%time:~3,2%"
    echo ✅ 主配置已提交
) else (
    echo ℹ️  主配置无变化，跳过提交
)

git push
if %errorlevel% equ 0 (
    echo ✅ 主配置已推送到 GitHub
) else (
    echo ❌ 主配置推送失败
)

echo.
echo [2/4] 同步工作区仓库 (workspace)
cd /d %USERPROFILE%\.openclaw\workspace
git add .

for /f "delims=" %%i in ('git diff --cached --name-only') do set HAS_CHANGES=%%i
if defined HAS_CHANGES (
    git commit -m "自动备份 %date:~0,4%-%date:~5,2%-%date:~8,2% %time:~0,2%:%time:~3,2%"
    echo ✅ 工作区已提交
) else (
    echo ℹ️  工作区无变化，跳过提交
)

git push
if %errorlevel% equ 0 (
    echo ✅ 工作区已推送到 GitHub
) else (
    echo ❌ 工作区推送失败
)

echo.
echo [3/4] 压缩完整备份到本地
cd /d %USERPROFILE%
if exist openclaw-backup.tar.gz del openclaw-backup.tar.gz
tar -czf openclaw-backup-%date:~0,4%%date:~5,2%%date:~8,2%.tar.gz .openclaw
echo ✅ 本地压缩备份已创建

echo.
echo [4/4] 清理旧备份（保留最近 3 个）
for /f "skip=3 delims=" %%f in ('dir /b /o-d openclaw-backup-*.tar.gz') do del "%%f"
echo ✅ 旧备份已清理

echo.
echo ========================================
echo    同步完成！
echo ========================================
echo.
pause

